import { useMemo, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { authService as accountService } from '@/api/auth/authService';
import { usePasswordPolicy, validatePassword } from '@/lib/passwordUtils';
import { getApiErrorMessage } from '@/api/app/apiError';
import { ROUTES } from '@/lib/routes';

import { AuthLayout } from '../layouts/AuthLayout';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { Button } from '@/shadcn/components/ui/button';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';

type ResetFormData = {
  email: string;
  token: string;
  newPassword: string;
  confirmPassword: string;
};

export default function ResetPassword() {
  const location = useLocation();
  const navigate = useNavigate();
  const { data: passwordPolicy } = usePasswordPolicy();

  const resetSchema = useMemo(() =>
    z.object({
      email: z.string().email(),
      token: z.string().min(1, 'Token is required'),
      newPassword: z.string()
        .min(1, 'Password is required')
        .superRefine((val, ctx) => {
          if (!passwordPolicy) return;
          const err = validatePassword(val, passwordPolicy);
          if (err) ctx.addIssue({ code: z.ZodIssueCode.custom, message: err });
        }),
      confirmPassword: z.string().min(1, 'Confirm password is required'),
    }).refine((data) => data.newPassword === data.confirmPassword, {
      message: "Passwords don't match",
      path: ["confirmPassword"],
    }),
    [passwordPolicy]
  );

  const queryParams = new URLSearchParams(location.search);
  const tokenFromUrl = queryParams.get('token') || '';
  const emailFromUrl = queryParams.get('email') || '';

  const initialEmail = emailFromUrl || location.state?.email || '';

  const { register, handleSubmit, formState: { errors, touchedFields }, watch, trigger } = useForm<ResetFormData>({
    resolver: zodResolver(resetSchema),
    defaultValues: {
      email: initialEmail,
      token: tokenFromUrl,
      newPassword: '',
      confirmPassword: ''
    }
  });

  const newPasswordValue = watch('newPassword');
  const confirmTouched = !!touchedFields.confirmPassword;
  useEffect(() => {
    if (confirmTouched) trigger('confirmPassword');
  }, [newPasswordValue, confirmTouched, trigger]);

  const mutation = useMutation({
    mutationFn: (data: ResetFormData) => {
      const { email, token, newPassword } = data;
      return accountService.resetPassword({ email, token, newPassword });
    },
    onSuccess: () => {
      toast.success('Password reset successful!');
      navigate(ROUTES.LOGIN);
    }
  });

  return (
    <AuthLayout>
      <div className="bg-card rounded-xl shadow-xl p-8 border border-border">
        <h2 className="text-xl font-semibold text-foreground mb-6 text-center">
          Set New Password
        </h2>

        {mutation.isError && (
          <Alert variant="destructive" className="mb-4">
            <AlertDescription>
              {getApiErrorMessage(mutation.error, 'Something went wrong. Please try again.')}
            </AlertDescription>
          </Alert>
        )}

        <form onSubmit={handleSubmit((data) => mutation.mutate(data))} className="space-y-5">

          <HarmonyInput
            label="Email"
            readOnly
            className="text-muted-foreground cursor-not-allowed"
            {...register('email')}
          />

          <HarmonyInput
            label="New Password"
            type="password"
            error={errors.newPassword?.message}
            {...register('newPassword')}
          />

          <HarmonyInput
            label="Confirm New Password"
            type="password"
            error={errors.confirmPassword?.message}
            {...register('confirmPassword')}
          />

          <Button type="submit" className="w-full" disabled={mutation.isPending}>
            {mutation.isPending && <Loader2 className="animate-spin" />}
            Update Password
          </Button>
        </form>
      </div>
    </AuthLayout>
  );
}
